headStyles:
body {
  background: var(--dark-bg);
}

/* Two-column layout */
.contact-wrapper {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3rem;
  margin-top: 2rem;
}

/* Form styles */
.contact-form {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}
.contact-form .form-group {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}
.contact-form label {
  font-family: "Montserrat", sans-serif;
  font-weight: 600;
  font-size: 0.95rem;
  color: var(--text-white);
}
.contact-form input,
.contact-form select,
.contact-form textarea {
  padding: 0.75rem;
  background-color: var(--dark-bg-light);
  border: 1px solid var(--dark-bg-lighter);
  color: var(--text-white);
  font-family: "Roboto Slab", serif;
  font-size: 1rem;
  border-radius: 6px;
  transition: border-color 0.2s;
}
.contact-form input:focus,
.contact-form select:focus,
.contact-form textarea:focus {
  outline: none;
  border-color: var(--color-blue);
}
.contact-form textarea {
  min-height: 150px;
  resize: vertical;
}

/* Contact info card */
.contact-info-card {
  background-color: var(--dark-bg-light);
  border: 1px solid var(--dark-bg-lighter);
  padding: 2rem;
  border-radius: 8px;
  display: flex;
  flex-direction: column;
  gap: 2rem;
  height: fit-content;
}
.info-section {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}
.info-section h3 {
  font-family: "Montserrat", sans-serif;
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: var(--text-light);
  font-weight: 700;
}
.info-section p,
.info-section a {
  font-family: "Roboto Slab", serif;
  color: var(--text-white);
  font-size: 1rem;
  text-decoration: none;
  transition: color 0.2s;
}
.info-section a:hover {
  color: var(--color-light-blue);
}
.social-links {
  display: flex;
  gap: 1rem;
  margin-top: 0.5rem;
}
.social-links a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  background-color: var(--dark-bg-lighter);
  border-radius: 6px;
  color: var(--text-white);
  text-decoration: none;
  font-family: "Montserrat", sans-serif;
  font-weight: 600;
  font-size: 0.85rem;
  transition: background-color 0.2s;
}
.social-links a:hover {
  background-color: var(--color-blue);
}

@media (max-width: 768px) {
  .contact-wrapper {
    grid-template-columns: 1fr;
    gap: 2rem;
  }
  .contact-info-card {
    height: auto;
  }
}
